import{_ as a,c as e,o as l,ag as n}from"./chunks/framework.B-XtCDNB.js";const F=JSON.parse('{"title":"Query Interface","description":"","frontmatter":{},"headers":[],"relativePath":"docs/query-api.md","filePath":"docs/query-api.md"}'),o={name:"docs/query-api.md"};function t(p,s,r,c,i,y){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="query-interface" tabindex="-1">Query Interface <a class="header-anchor" href="#query-interface" aria-label="Permalink to &quot;Query Interface&quot;">​</a></h1><p>LinkedQL is designed around a stable application-facing API.</p><p>Across the supported runtimes, you keep the same core concepts:</p><ul><li><code>db.query()</code> for regular SQL execution and live queries</li><li><code>db.stream()</code> for lazy row-by-row reads</li><li><code>db.transaction()</code> for explicit transactions</li><li><code>db.wal.subscribe()</code> for table-level changefeeds</li></ul><p>That common surface is the contract, whether <code>db</code> is:</p><ul><li>a mainstream database client such as <code>PGClient</code>, <code>MySQLClient</code>, and <code>MariaDBClient</code></li><li><code>EdgeClient</code>, which talks to a remote worker or server over transport</li><li><code>FlashQL</code>, which runs the engine locally in-process</li></ul><h2 id="db-query" tabindex="-1"><code>db.query()</code> <a class="header-anchor" href="#db-query" aria-label="Permalink to &quot;\`db.query()\`&quot;">​</a></h2><p><code>query()</code> is the primary method for executing SQL statements.</p><p>It supports several invocation forms.</p><h3 id="signatures" tabindex="-1">Signatures <a class="header-anchor" href="#signatures" aria-label="Permalink to &quot;Signatures&quot;">​</a></h3><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(sql: string): </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">Result</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#BABED8;">db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(sql: string</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> values: any[]): </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">Result</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#BABED8;">db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(sql: string</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> options: QueryOptions): </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">Result</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#BABED8;">db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(sql: string</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> callback: Function</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> options: QueryOptions): </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">RealtimeResult</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#BABED8;">db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(queryLike: </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> query</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> string; </span><span style="color:#89DDFF;">...</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">): </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">Result</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#BABED8;">db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(queryLike: </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> text</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> string; </span><span style="color:#89DDFF;">...</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">): </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">&lt;</span><span style="color:#BABED8;">Result</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h3 id="general-behavior" tabindex="-1">General behavior <a class="header-anchor" href="#general-behavior" aria-label="Permalink to &quot;General behavior&quot;">​</a></h3><p><code>query()</code>:</p><ul><li>executes the provided SQL text</li><li>accepts parameters either positionally or through <code>options.values</code></li><li>accepts runtime options such as <code>dialect</code>, <code>live</code>, <code>signal</code>, <code>id</code>, or <code>tx</code></li><li>returns either a <code>Result</code> or, for live queries, a <code>RealtimeResult</code></li></ul><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><h4 id="basic-query-execution" tabindex="-1">Basic query execution <a class="header-anchor" href="#basic-query-execution" aria-label="Permalink to &quot;Basic query execution&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This executes the query and buffers the full result set into <code>result.rows</code>.</p><h4 id="parameterized-query" tabindex="-1">Parameterized query <a class="header-anchor" href="#parameterized-query" aria-label="Permalink to &quot;Parameterized query&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM users WHERE active = $1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> [</span><span style="color:#FF9CAC;">true</span><span style="color:#BABED8;">])</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is the same query API, with positional parameters.</p><h4 id="query-with-options" tabindex="-1">Query with options <a class="header-anchor" href="#query-with-options" aria-label="Permalink to &quot;Query with options&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM users WHERE created_at &gt;= $1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#F07178;">  values</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">new</span><span style="color:#82AAFF;"> Date</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">2026-01-01</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)]</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This form keeps values and execution options in one object.</p><h4 id="parameters-through-options-values" tabindex="-1">Parameters through <code>options.values</code> <a class="header-anchor" href="#parameters-through-options-values" aria-label="Permalink to &quot;Parameters through \`options.values\`&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM users WHERE name = $1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> values</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Use this form when you want option-based invocation without a separate values array argument.</p><h4 id="live-query-form" tabindex="-1">Live query form <a class="header-anchor" href="#live-query-form" aria-label="Permalink to &quot;Live query form&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT id, title FROM posts ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>In live mode, the query stays open and <code>result.rows</code> becomes a live view.</p><h4 id="live-query-with-callback" tabindex="-1">Live query with callback <a class="header-anchor" href="#live-query-with-callback" aria-label="Permalink to &quot;Live query with callback&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> commits </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> []</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, title FROM posts ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> commits</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">push</span><span style="color:#BABED8;">(commit)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>The callback form is also for live queries, but it changes the delivery model.</p><p>With a callback present:</p><ul><li><code>result.rows</code> carries the initial result set</li><li>subsequent updates are emitted to the callback as commit events</li><li><code>result.mode</code> tells you how that <code>RealtimeResult</code> is being delivered</li></ul><p>In other words, the callback form is the commit-stream interface, not the self-updating <code>rows</code> interface.</p><h2 id="result" tabindex="-1"><code>Result</code> <a class="header-anchor" href="#result" aria-label="Permalink to &quot;\`Result\`&quot;">​</a></h2><p><code>Result</code> represents the outcome of a regular query.</p><p>All non-live <code>query()</code> operations return a <code>Result</code> object that can contain both row data and write metadata, though only one of those is meaningful for a given statement.</p><h3 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>rows</code></td><td style="text-align:left;"><code>any[]</code></td><td style="text-align:left;">Result set as an array of row objects</td></tr><tr><td style="text-align:left;"><code>rowCount</code></td><td style="text-align:left;"><code>number</code></td><td style="text-align:left;">Number of rows affected by a non-returning write</td></tr><tr><td style="text-align:left;"><code>affectedRows</code></td><td style="text-align:left;"><code>number</code></td><td style="text-align:left;">Alias of <code>rowCount</code>, useful for MySQL/MariaDB-style code</td></tr></tbody></table><h3 id="reading-result-correctly" tabindex="-1">Reading <code>Result</code> correctly <a class="header-anchor" href="#reading-result-correctly" aria-label="Permalink to &quot;Reading \`Result\` correctly&quot;">​</a></h3><p><code>rowCount</code> is not the number of returned rows.</p><p>It is instead the number of rows affected by an <code>INSERT</code>, <code>UPDATE</code>, or <code>DELETE</code> that does not itself return rows.</p><p>Quick reference:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Operation</th><th style="text-align:left;">Returns <code>rows</code></th><th style="text-align:left;">Affects <code>rowCount</code></th></tr></thead><tbody><tr><td style="text-align:left;"><code>SELECT</code></td><td style="text-align:left;">yes</td><td style="text-align:left;">no</td></tr><tr><td style="text-align:left;"><code>INSERT/UPDATE/DELETE ... RETURNING</code></td><td style="text-align:left;">yes</td><td style="text-align:left;">no</td></tr><tr><td style="text-align:left;"><code>INSERT/UPDATE/DELETE</code></td><td style="text-align:left;">no</td><td style="text-align:left;">yes</td></tr></tbody></table><h3 id="examples-1" tabindex="-1">Examples <a class="header-anchor" href="#examples-1" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><h4 id="a-fetch-operation" tabindex="-1">A fetch operation <a class="header-anchor" href="#a-fetch-operation" aria-label="Permalink to &quot;A fetch operation&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT id, name FROM users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ id: 1, name: &#39;Ada&#39; }]</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rowCount)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 0</span></span></code></pre></div><p><code>rowCount</code> stays <code>0</code> here because this is a read query. The returned rows live in <code>result.rows</code>.</p><h4 id="a-write-operation-with-returning" tabindex="-1">A write operation with <code>RETURNING</code> <a class="header-anchor" href="#a-write-operation-with-returning" aria-label="Permalink to &quot;A write operation with \`RETURNING\`&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">INSERT INTO users (name) VALUES ($1) RETURNING *</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#BABED8;">  [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Bob</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">]</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ id: 2, name: &#39;Bob&#39; }]</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rowCount)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 0</span></span></code></pre></div><p><code>RETURNING</code> turns the write into a result-set query, so the inserted rows come back in <code>rows</code>.</p><h4 id="a-write-operation-without-returning" tabindex="-1">A write operation without <code>RETURNING</code> <a class="header-anchor" href="#a-write-operation-without-returning" aria-label="Permalink to &quot;A write operation without \`RETURNING\`&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">INSERT INTO users (name) VALUES ($1)</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#BABED8;">  [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Eve</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">]</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rowCount)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 1</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// []</span></span></code></pre></div><p>Without <code>RETURNING</code>, the write reports through <code>rowCount</code> instead.</p><h2 id="realtimeresult" tabindex="-1"><code>RealtimeResult</code> <a class="header-anchor" href="#realtimeresult" aria-label="Permalink to &quot;\`RealtimeResult\`&quot;">​</a></h2><p><code>RealtimeResult</code> is the result of a <a href="/capabilities/live-queries">live query</a>: a query executed with <code>{ live: true }</code>.</p><p>It extends the ordinary idea of a <code>Result</code> into a live view of query results that continues to reflect the underlying dataset over time.</p><h3 id="properties-1" tabindex="-1">Properties <a class="header-anchor" href="#properties-1" aria-label="Permalink to &quot;Properties&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>rows</code></td><td style="text-align:left;"><code>any[]</code></td><td style="text-align:left;">Result rows for the <code>RealtimeResult</code>; in callback-free live mode this is the self-updating live view, while in callback mode it carries the initial result set</td></tr><tr><td style="text-align:left;"><code>hashes</code></td><td style="text-align:left;"><code>string[]</code></td><td style="text-align:left;">Internal row identifiers used for diff tracking</td></tr><tr><td style="text-align:left;"><code>mode</code></td><td style="text-align:left;"><code>string</code></td><td style="text-align:left;">Delivery mode such as <code>&#39;live&#39;</code>, <code>&#39;streaming&#39;</code>, or <code>&#39;streaming_only&#39;</code>; this tells you how <code>rows</code> and commits are being delivered</td></tr></tbody></table><p>Treat <code>rows</code> and <code>hashes</code> as read-only. Manual mutation can desynchronize the internal state that keeps the live result coherent.</p><h3 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h3><h4 id="await-result-abort" tabindex="-1"><code>await result.abort()</code> <a class="header-anchor" href="#await-result-abort" aria-label="Permalink to &quot;\`await result.abort()\`&quot;">​</a></h4><p>Terminates the live query and stops further updates to the live view.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If the live query was created with a stable <code>id</code>, pass <code>{ forget: true }</code> to also drop the internal slot bound to that <code>id</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> forget</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>That ends reactivity. The array stops updating.</p><h3 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h3><p><code>RealtimeResult</code> is the result type for live queries.</p><p>How you consume it depends on <code>mode</code>:</p><ul><li>in live-view mode, <code>rows</code> is the self-updating query result</li><li>in callback-driven mode, <code>rows</code> is the initial result and later updates arrive as commits</li></ul><p>Once aborted, the live result stops advancing.</p><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, name FROM users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// current rows; this array keeps mutating as the query stays live</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">mode)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// &#39;live&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="observing-mutations" tabindex="-1">Observing mutations <a class="header-anchor" href="#observing-mutations" aria-label="Permalink to &quot;Observing mutations&quot;">​</a></h3><p>Because live rows are implemented through the Observer protocol, they can be observed like other mutatable JavaScript objects:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> Observer</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@webqit/observer</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">Observer</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">observe</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> Observer</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subtree</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">mutations</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">mutations</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This exposes the mutations applied to the live result as it changes over time.</p><p>At root level, you observe row additions and removals. With <code>Observer.subtree()</code>, you also observe field-level changes inside the live rows.</p><h2 id="db-stream" tabindex="-1"><code>db.stream()</code> <a class="header-anchor" href="#db-stream" aria-label="Permalink to &quot;\`db.stream()\`&quot;">​</a></h2><p><code>stream()</code> is the lazy, pull-based alternative to <code>query()</code>.</p><p>Use it when:</p><ul><li>the result may be large</li><li>you do not want all rows buffered into memory first</li><li>you want <code>for await ... of</code> iteration</li></ul><p>This is not the same thing as a live query. A stream iterates over one query execution. A live query stays open and continues reacting to future changes.</p><h3 id="example-1" tabindex="-1">Example <a class="header-anchor" href="#example-1" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, email</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><h2 id="db-transaction" tabindex="-1"><code>db.transaction()</code> <a class="header-anchor" href="#db-transaction" aria-label="Permalink to &quot;\`db.transaction()\`&quot;">​</a></h2><p><code>transaction(cb)</code> creates an explicit transactional scope.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">  // do multiple things atomically</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If the callback resolves, LinkedQL commits. If it throws, LinkedQL rolls back.</p><p>The callback shape is stable across runtimes, but the transaction object <code>tx</code> itself is runtime-specific.</p><h3 id="mainstream-database-example" tabindex="-1">Mainstream database example <a class="header-anchor" href="#mainstream-database-example" aria-label="Permalink to &quot;Mainstream database example&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#F07178;">(</span></span>
<span class="line"><span style="color:#89DDFF;">    &#39;</span><span style="color:#C3E88D;">INSERT INTO users (id, name) VALUES ($1, $2)</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">    {</span><span style="color:#F07178;"> values</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> [</span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#F07178;">]</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#F07178;">  )</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#F07178;">(</span></span>
<span class="line"><span style="color:#89DDFF;">    &#39;</span><span style="color:#C3E88D;">UPDATE users SET active = true WHERE id = $1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">    {</span><span style="color:#F07178;"> values</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> [</span><span style="color:#F78C6C;">1</span><span style="color:#F07178;">]</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#F07178;">  )</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="flashql-example" tabindex="-1">FlashQL example <a class="header-anchor" href="#flashql-example" aria-label="Permalink to &quot;FlashQL example&quot;">​</a></h3><p>FlashQL works the same as above. But it additionally exposes DDL and DML methods on <code>tx</code> object itself:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> flash</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#C792EA;">  const</span><span style="color:#BABED8;"> table</span><span style="color:#89DDFF;"> =</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getTable</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> table</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">insert</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is the same transactional scope, but with FlashQL&#39;s lower-level transaction surface available directly on <code>tx</code>.</p><h3 id="transaction-rules-worth-knowing" tabindex="-1">Transaction rules worth knowing <a class="header-anchor" href="#transaction-rules-worth-knowing" aria-label="Permalink to &quot;Transaction rules worth knowing&quot;">​</a></h3><ul><li>if the callback resolves, LinkedQL commits</li><li>if the callback throws, LinkedQL rolls back and re-throws</li><li>live queries are not supported inside explicit transactions</li></ul><h2 id="db-wal-subscribe" tabindex="-1"><code>db.wal.subscribe()</code> <a class="header-anchor" href="#db-wal-subscribe" aria-label="Permalink to &quot;\`db.wal.subscribe()\`&quot;">​</a></h2><p><code>db.wal.subscribe()</code> is LinkedQL&#39;s table-level changefeed API.</p><p>Use it when you care about table mutations directly rather than about a query result.</p><h3 id="minimal-form" tabindex="-1">Minimal form <a class="header-anchor" href="#minimal-form" aria-label="Permalink to &quot;Minimal form&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">(</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This subscribes to table-level commits without filtering.</p><h3 id="filtered-form" tabindex="-1">Filtered form <a class="header-anchor" href="#filtered-form" aria-label="Permalink to &quot;Filtered form&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">orders</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">    console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">entries</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">  }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This narrows the feed to the selected relations.</p><h3 id="stable-subscription-slots" tabindex="-1">Stable subscription slots <a class="header-anchor" href="#stable-subscription-slots" aria-label="Permalink to &quot;Stable subscription slots&quot;">​</a></h3><p>You can also attach an id to a subscription:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">    console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">  },</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users_slot</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>That id is more than a label. It gives the subscription a durable slot identity, and LinkedQL binds that subscription to the same slot each time it is recreated with the same id.</p><p>With that slot identity, the runtime:</p><ul><li>resumes from the same logical slot</li><li>catches up on commits that were missed while the subscriber was away</li><li>avoids treating every reconnect as a brand-new subscription</li></ul><p>That matters when changefeeds back application caches, replicas, sync workers, or long-lived UI sessions that must continue from a known point rather than restarting blindly from &quot;now.&quot;</p><p>To drop the slot itself, pass <code>{ forget: true }</code> to the <code>unsubscribe()</code> call:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#82AAFF;"> unsubscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> forget</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="what-commit-objects-contain" tabindex="-1">What commit objects contain <a class="header-anchor" href="#what-commit-objects-contain" aria-label="Permalink to &quot;What commit objects contain&quot;">​</a></h3><p>At minimum, table-level commits contain entries that tell you:</p><ul><li>which relation changed</li><li>what operation happened</li><li>the old and new row image where applicable</li></ul><p>This is the right layer when you want raw mutation visibility and intend to build your own projection, cache, or replication logic.</p><h2 id="one-contract-multiple-layers" tabindex="-1">One contract, multiple layers <a class="header-anchor" href="#one-contract-multiple-layers" aria-label="Permalink to &quot;One contract, multiple layers&quot;">​</a></h2><p>LinkedQL keeps the way you talk to data stable even when the place where the data lives changes.</p><p>Richer layers such as live queries, FlashQL orchestration, federation, and sync build on top of that contract.</p><p>Continue with:</p><ul><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/capabilities/changefeeds">Changefeeds</a></li><li><a href="/capabilities/streaming">Streaming</a></li><li><a href="/flashql">FlashQL</a></li></ul>`,128)])])}const d=a(o,[["render",t]]);export{F as __pageData,d as default};
